content:
:root {
    --neon-blue: #0ff;
    --neon-purple: #f0f;
    --neon-green: #0f0;
    --dark-bg: #0a0a0a;
    --darker-bg: #050505;
    --text-color: #eee;
    --error-color: #f00;
}

@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700&family=Share+Tech+Mono&display=swap');

body {
    margin: 0;
    font-family: 'Share Tech Mono', monospace;
    background-color: var(--darker-bg);
    color: var(--text-color);
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    overflow: hidden; /* Hide potential overflow from scanlines/glitch */
    position: relative;
    isolation: isolate; /* Create a new stacking context for ::before */
}

/* Scanline Effect */
body::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: repeating-linear-gradient(
        to bottom,
        rgba(0, 0, 0, 0.1) 0px,
        rgba(0, 0, 0, 0.1) 1px,
        transparent 1px,
        transparent 2px
    );
    pointer-events: none;
    animation: scanline-flicker 15s infinite linear;
    z-index: -1;
}

@keyframes scanline-flicker {
    0% { background-position: 0 0; }
    100% { background-position: 0 100vh; /* Move scanlines down */ }
}

.login-container {
    background-color: var(--dark-bg);
    padding: 40px;
    border: 2px solid var(--neon-blue);
    box-shadow:
        0 0 15px var(--neon-blue),
        inset 0 0 10px var(--neon-blue);
    border-radius: 8px;
    text-align: center;
    max-width: 400px;
    width: 90%;
    animation: neon-pulse 2.5s infinite alternate;
    position: relative;
    z-index: 1;
}

.login-title {
    font-family: 'Orbitron', sans-serif;
    font-size: 2.2em;
    color: var(--neon-blue);
    text-shadow: 0 0 10px var(--neon-blue);
    margin-bottom: 30px;
    position: relative;
    animation: text-glitch 4s infinite linear alternate;
}

.login-form .form-group {
    margin-bottom: 20px;
    text-align: left;
    position: relative; /* For glitch effect on labels */
}

.login-form label {
    display: block;
    margin-bottom: 8px;
    color: var(--neon-green);
    text-shadow: 0 0 5px var(--neon-green);
    font-size: 1.1em;
    position: relative;
    animation: label-glitch 8s infinite steps(1);
}

.login-form input[type="text"],
.login-form input[type="password"] {
    width: calc(100% - 20px);
    padding: 12px 10px;
    background-color: rgba(0, 0, 0, 0.7);
    border: 1px solid var(--neon-blue);
    color: var(--neon-green);
    font-family: 'Share Tech Mono', monospace;
    font-size: 1em;
    box-shadow: 0 0 5px var(--neon-blue), inset 0 0 3px var(--neon-blue);
    transition: all 0.3s ease-in-out;
}

.login-form input[type="text"]:focus,
.login-form input[type="password"]:focus {
    outline: none;
    border-color: var(--neon-purple);
    box-shadow: 0 0 10px var(--neon-purple), inset 0 0 5px var(--neon-purple);
}

.login-button {
    background-color: var(--neon-blue);
    color: var(--dark-bg);
    border: none;
    padding: 15px 30px;
    font-family: 'Orbitron', sans-serif;
    font-size: 1.2em;
    cursor: pointer;
    box-shadow: 0 0 15px var(--neon-blue);
    transition: all 0.3s ease-in-out;
    animation: neon-button-glow 3s infinite alternate;
    margin-top: 20px;
    width: 100%;
    text-transform: uppercase;
}

.login-button:hover {
    background-color: var(--neon-purple);
    box-shadow: 0 0 25px var(--neon-purple);
    transform: translateY(-2px);
}

.error-message {
    color: var(--error-color);
    font-size: 1em;
    margin-top: 20px;
    text-shadow: 0 0 5px var(--error-color);
    animation: error-flicker 0.5s infinite alternate;
}

/* Keyframe Animations */
@keyframes neon-pulse {
    from {
        box-shadow:
            0 0 15px var(--neon-blue),
            inset 0 0 10px var(--neon-blue);
    }
    to {
        box-shadow:
            0 0 25px var(--neon-blue),
            inset 0 0 15px var(--neon-blue);
    }
}

@keyframes neon-button-glow {
    0% {
        box-shadow: 0 0 10px var(--neon-blue);
    }
    50% {
        box-shadow: 0 0 20px var(--neon-blue), 0 0 30px var(--neon-blue);
    }
    100% {
        box-shadow: 0 0 10px var(--neon-blue);
    }
}

@keyframes text-glitch {
    0% { transform: translate(0, 0); text-shadow: 0 0 10px var(--neon-blue); }
    10% { transform: translate(-1px, 1px); text-shadow: 1px 0 10px var(--neon-purple), -1px 0 10px var(--neon-green); }
    20% { transform: translate(1px, -1px); text-shadow: -1px 0 10px var(--neon-purple), 1px 0 10px var(--neon-green); }
    30% { transform: translate(0, 0); text-shadow: 0 0 10px var(--neon-blue); }
    32% { opacity: 0.9; }
    34% { opacity: 1; }
    40% { transform: translate(-0.5px, 0.5px); text-shadow: 0.5px 0 8px var(--neon-blue); }
    50% { transform: translate(0.5px, -0.5px); text-shadow: -0.5px 0 8px var(--neon-blue); }
    60% { transform: translate(0, 0); text-shadow: 0 0 10px var(--neon-blue); }
    70% { opacity: 0.95; }
    80% { opacity: 1; }
    90% { transform: translate(1px, 0); text-shadow: 0 0 12px var(--neon-blue); }
    100% { transform: translate(0, 0); text-shadow: 0 0 10px var(--neon-blue); }
}

@keyframes label-glitch {
    0% { clip-path: inset(0 0 0 0); }
    2% { clip-path: inset(0 0 90% 0); }
    4% { clip-path: inset(0 0 0 0); }
    6% { clip-path: inset(10% 0 0 0); }
    8% { clip-path: inset(0 0 0 0); }
    10% { clip-path: inset(50% 0 0 0); }
    12% { clip-path: inset(0 0 0 0); }
    100% { clip-path: inset(0 0 0 0); }
}

@keyframes error-flicker {
    0%, 100% { opacity: 1; text-shadow: 0 0 5px var(--error-color); }
    50% { opacity: 0.7; text-shadow: 0 0 10px var(--error-color), 0 0 15px var(--error-color); }
}

/* Dashboard styles (integrated) */
.message-container {
    text-align: center;
    padding: 40px;
    border: 2px solid var(--neon-blue);
    box-shadow: 0 0 15px var(--neon-blue), inset 0 0 10px var(--neon-blue);
    animation: neon-pulse 1.5s infinite alternate;
    background-color: var(--dark-bg);
    border-radius: 8px;
    max-width: 500px;
    width: 90%;
    position: relative;
    z-index: 1;
}

.message-container h1 {
    font-family: 'Orbitron', sans-serif;
    font-size: 3em;
    margin-bottom: 20px;
    color: var(--neon-blue);
    text-shadow: 0 0 10px var(--neon-blue);
}

.message-container p {
    font-size: 1.2em;
    margin-bottom: 10px;
    color: var(--neon-green);
    text-shadow: 0 0 5px var(--neon-green);
}

.message-container p:last-of-type {
    margin-top: 30px;
}

.message-container a {
    color: var(--neon-blue);
    text-decoration: none;
    border-bottom: 1px dotted var(--neon-blue);
    transition: all 0.3s ease;
    text-shadow: 0 0 5px var(--neon-blue);
}

.message-container a:hover {
    color: var(--neon-purple);
    border-bottom-color: var(--neon-purple);
    text-shadow: 0 0 10px var(--neon-purple);
}
